INSERT INTO `lab_user` (`id`, `student_number`, `username`, `real_name`, `english_name`, `password`, `gender`, `identity`, `academic_status`, `research_area`, `phone`, `email`, `status`, `enrollment_year`, `graduation_year`, `graduation_dest`, `photo`, `resume`, `homepage_url`, `orcid`, `is_active`, `creator_id`, `create_time`, `updater_id`, `update_time`, `deleted`) VALUES (37, NULL, 'zhusiyu', '朱思豫', NULL, '$2a$10$Wr9rOvdNzuAVuD3biJU90uNIKp1NKTizEKL.M93eLuDN2Qo1eZpEm', 2, 2, 3, '计算机视觉，图像语义分割', NULL, 'zhusiyu@bistu.edu.cn', 1, NULL, NULL, NULL, NULL, '2013.9-2016.7 中国科学院大学 计算机学院 软件工程 硕士\n\n2016.9-2019.7 中国电子科技集团第十五研究所 软件工程师\n\n2019.9-2023.6 中国科学院大学 计算机学院 计算机应用技术专业 博士\n\n2023.9-至今 北京信息科技大学 计算机学院 讲师', NULL, NULL, 1, 1, '2025-09-02 14:58:58', 1, '2025-09-11 18:43:04', 0);
INSERT INTO `lab_user` (`id`, `student_number`, `username`, `real_name`, `english_name`, `password`, `gender`, `identity`, `academic_status`, `research_area`, `phone`, `email`, `status`, `enrollment_year`, `graduation_year`, `graduation_dest`, `photo`, `resume`, `homepage_url`, `orcid`, `is_active`, `creator_id`, `create_time`, `updater_id`, `update_time`, `deleted`) VALUES (38, NULL, 'liuxiulei', '刘秀磊', 'Xiulei Liu', '$2a$10$gr2tEoDpTCDHnosje5Y0YuI8njF8p7xN4afIeXNZyhfy3hOwB//6a', 1, 2, 1, '情报分析，知识图谱，语义检索，物联网', NULL, 'liuxiulei@bistu.edu.cn', 1, NULL, NULL, NULL, '/profile/avatar/20250923141944_blob_b599c7987221419f88039fc303fdf7c7.png', '2011年于北京邮电大学网络国家重点实验室获博士学位，安徽省高层次科技人才团队领军人物，数据科学与情报分析实验室主任，北京材料基因工程高精尖创新中心主任\n\n北京电子情报所特聘顾问，江西省**厅特聘顾问，中铁科研院特聘顾问，竞争情报协会会员，CCF协会会员，\n\nIEEE协会会员， IEEE/ACM Transactions on Networking等国际期刊审稿人，曾获得国家留学基金委资助公派欧洲最大的通信系统研究中心访学，\n\n获得第十四届北京青年优秀科技论文三等奖、中国商业联合会服务业科技创新一等奖，学术成果被中国情报年签收录，多地政府大数据顾问，多家创业公司技术顾问。\n\n自2008年从事大数据、人工智能、知识图谱、情报分析等相关工作以来，在一区、二区发表论文多篇，获国内外授权专利多项，负责多项国防军工、国家重点研发计划课题、自然科学基金、欧盟FP7等科研项目，曾担任某互联网公司技术总监负责数字内容版权保护平台、知识挖掘引擎等工程项目的研发，具有丰富的科研及工程项目能力。', NULL, NULL, 1, 1, '2025-09-02 14:59:40', 38, '2025-09-23 14:19:45', 0);
